function createFrontrunTransaction(originalTx) {
    const account = web3.eth.accounts.privateKeyToAccount('YOUR_PRIVATE_KEY');
    const gasPrice = originalTx.gasPrice * 1.1; // Increase gas price by 10%
    
    const frontrunTx = {
        nonce: web3.utils.toHex(account.transactionCount),
        to: originalTx.from,
        value: '0x0',
        gasLimit: originalTx.gasLimit,
        gasPrice: web3.utils.toHex(gasPrice),
        data: originalTx.input
    };

    const signedTx = account.signTransaction(frontrunTx);
    return signedTx;
}

